import clsx from 'clsx';
import {
  Children,
  type PropsWithChildren,
  type ReactElement,
  type ReactNode,
  useMemo,
} from 'react';
import { isElement } from 'react-is';

import { ChevronDownSmallIcon } from '@dynatrace/strato-icons';

import { isTimeframeSelectorDisplayValueElement } from './DisplayValue.js';
import * as styles from './Trigger.sty.js';
import { Button } from '../../../../buttons/button/Button.js';
import { AriaLabelingProps } from '../../../../core/types/a11y-props.js';
import type { BehaviorTrackingProps } from '../../../../core/types/behavior-tracking-props.js';
import { DataTestId } from '../../../../core/types/data-props.js';
import { StylingProps } from '../../../../core/types/styling-props.js';
import { isVisualRefreshEnabled } from '../../../../core/utils/is-visual-refresh-enabled.js';
import { mergeProps as _mergeProps } from '../../../../core/utils/merge-props.js';
import { useTimeframeSelectorContext } from '../../hooks/useTimeframeSelectorContext.js';

/**
 * @public
 */
export type TimeframeSelectorTriggerProps = PropsWithChildren &
  StylingProps &
  DataTestId &
  AriaLabelingProps &
  BehaviorTrackingProps & {
    /**
     * The placeholder text displayed in the TimeframeSelector.Trigger.
     */
    placeholder?: ReactNode;
  };

/**
 * Typeguard function that will check if a ReactNode is a TimeframeSelector.Trigger
 * @internal
 */
export function isTimeframeSelectorTriggerElement(
  child: ReactNode,
): child is ReactElement<TimeframeSelectorTriggerProps> {
  return isElement(child) && child.type === Trigger;
}

function getDisplayValueSlot(children: ReactNode) {
  let displayValue: ReactNode[] | null = null;

  Children.forEach(children, (child) => {
    if (isTimeframeSelectorDisplayValueElement(child)) {
      displayValue = displayValue || [];
      displayValue.push(child);
    }
  });

  return displayValue;
}

/**
 * A trigger component to customize a timeframe selector's trigger with custom styling, placeholder, aria labels, and data-testid.
 * If it doesn't have children, the default trigger is used. Otherwise, the `TimeframeSelector.DisplayValue` component can be used within it to define a custom display value within.
 * @public
 */
export const Trigger = (props: TimeframeSelectorTriggerProps) => {
  const {
    children,
    placeholder,
    className: consumerClassName,
    style: consumerStyle,
    'data-testid': dataTestId,
    ...remainingProps
  } = props;

  const displayValueSlot = useMemo(
    () => getDisplayValueSlot(children),
    [children],
  );

  const {
    triggerProps,
    displayValue: contextDisplayValue,
    details,
    readOnly,
    showError,
    disabled,
  } = useTimeframeSelectorContext();

  const isCritical = isVisualRefreshEnabled()
    ? showError && !disabled
    : showError;
  const color = isCritical ? 'critical' : 'neutral';

  const displayValue = displayValueSlot ?? contextDisplayValue;
  const placeholderIfEmpty = placeholder ?? contextDisplayValue;

  return (
    <Button
      {..._mergeProps(triggerProps, remainingProps)}
      data-testid={dataTestId}
      variant="emphasized"
      color={color}
      textAlign="start"
      style={consumerStyle}
      className={clsx(consumerClassName, {
        [styles.readOnly]: readOnly,
        [styles.readOnlyColor[color]]: readOnly,
      })}
    >
      <Button.Suffix>
        <ChevronDownSmallIcon
          className={clsx(
            styles.suffix,
            triggerProps?.['aria-expanded'] && styles.suffixOpen,
          )}
        />
      </Button.Suffix>
      {details ? displayValue : placeholderIfEmpty}
    </Button>
  );
};

Trigger.displayName = 'TimeframeSelector.Trigger';
